215	    @Override
216	    protected void doBuild() throws Exception {
217	        ServiceHelper.buildService(processor);
218	    }
219	
220	    @Override
221	    protected void doInit() throws Exception {
222	        ServiceHelper.initService(processor);
223	    }
224	
225	    @Override
226	    protected void doStart() throws Exception {
227	        ServiceHelper.startService(processor);
228	        delivery = new Delivery();
229	        engine.start();
230	        delivery.start();
231	    }
232	
233	    @Override
234	    protected void doStop() throws Exception {
235	        // let's stop everything in the reverse order
236	        // no need to stop the worker thread -- it will stop automatically when this service is stopped
237	        engine.stop();
238	        ServiceHelper.stopService(processor);
239	    }
240	
241	    /**
242	     * Sends the <code>exchange</code> to the next <code>processor</code>.
243	     *
244	     * @param exchange exchange to send.
245	     */
246	    @Override
247	    public void sendElement(Exchange exchange) throws Exception {
248	        processor.process(exchange);
249	    }
250	
251	    @Override
252	    public boolean process(Exchange exchange, AsyncCallback callback) {
253	        try {
254	            engine.waitUntil(s -> s.size() < capacity);
255	        } catch (InterruptedException e) {
256	            Thread.currentThread().interrupt();
257	            // we were interrupted so break out
258	            exchange.setException(e);
259	            callback.done(true);
260	            return true;
261	        }
262	
263	        try {
264	            // need to make defensive copy that are put on the sequencer queue
265	            Exchange copy = ExchangeHelper.createCorrelatedCopy(exchange, true);
266	            engine.insert(copy);
267	            delivery.request();
268	        } catch (Exception e) {
269	            if (isIgnoreInvalidExchanges()) {
270	                LOG.debug("Invalid Exchange. This Exchange will be ignored: {}", exchange);
271	            } else {
272	                exchange.setException(
273	                        new CamelExchangeException("Error processing Exchange in StreamResequencer", exchange, e));
274	            }
275	        }
276	
277	        callback.done(true);
278	        return true;
279	    }
280	
281	    @Override
282	    public boolean hasNext() {
283	        return processor != null;
284	    }
285	
286	    @Override
287	    public List<Processor> next() {
288	        if (!hasNext()) {
289	            return null;
290	        }
291	        List<Processor> answer = new ArrayList<>(1);
292	        answer.add(processor);
293	        return answer;
294	    }
295	
296	    class Delivery extends Thread {
297	
298	        private final Lock deliveryRequestLock = new ReentrantLock();
299	        private final Condition deliveryRequestCondition = deliveryRequestLock.newCondition();
300	
301	        Delivery() {
302	            super(camelContext.getExecutorServiceManager().resolveThreadName("Resequencer Delivery"));
303	        }
304	
305	        @Override
306	        public void run() {
307	            while (isRunAllowed()) {
308	                try {
309	                    deliveryRequestLock.lock();
310	                    try {
311	                        deliveryRequestCondition.await(deliveryAttemptInterval, TimeUnit.MILLISECONDS);
312	                    } finally {
313	                        deliveryRequestLock.unlock();
314	                    }
315	                } catch (InterruptedException e) {
316	                    Thread.currentThread().interrupt();
317	                    break;
318	                }
319	                try {
320	                    engine.deliver();
321	                } catch (Exception t) {
322	                    // a fail-safe to handle all exceptions being thrown
323	                    getExceptionHandler().handleException(t);
324	                }
325	            }
326	        }
327	
328	        public void cancel() {
329	            interrupt();
330	        }
331	
332	        public void request() {
333	            deliveryRequestLock.lock();
334	            try {
335	                deliveryRequestCondition.signal();
336	            } finally {
337	                deliveryRequestLock.unlock();
338	            }
339	        }
340	
341	    }
342	
343	}
