18	
19	import java.util.concurrent.locks.Lock;
20	import java.util.concurrent.locks.ReentrantLock;
21	
22	/**
23	 * A container for objects to be resequenced. This container can be scheduled for timing out. Non-scheduled objects or
24	 * already timed-out objects are ready for being released by the {@link ResequencerEngine}.
25	 */
26	class Element<E> implements TimeoutHandler {
27	
28	    private final Lock lock = new ReentrantLock();
29	    /**
30	     * The contained object.
31	     */
32	    private final E object;
33	
34	    /**
35	     * Not <code>null</code> if this element is currently beeing scheduled for timing out.
36	     */
37	    private Timeout timeout;
38	
39	    /**
40	     * Creates a new container instance.
41	     *
42	     * @param object contained object.
43	     */
44	    Element(E object) {
45	        this.object = object;
46	    }
47	
48	    /**
49	     * Returns the contained object.
50	     *
51	     * @return the contained object.
52	     */
53	    public E getObject() {
54	        return object;
55	    }
56	
57	    /**
58	     * Returns <code>true</code> if this element is currently scheduled for timing out.
59	     *
60	     * @return <code>true</code> if scheduled or <code>false</code> if not scheduled or already timed-out.
61	     */
62	    public boolean scheduled() {
63	        lock.lock();
64	        try {
65	            return timeout != null;
66	        } finally {
67	            lock.unlock();
68	        }
69	    }
70	
71	    /**
72	     * Schedules the given timeout task. Before this methods calls the {@link Timeout#schedule()} method it sets this
73	     * element as timeout listener.
74	     *
75	     * @param t a timeout task.
76	     */
77	    public void schedule(Timeout t) {
78	        lock.lock();
79	        try {
80	            this.timeout = t;
