    /**
     * Wraps a {@link SequenceElementComparator} to deliver its elements in reverse (descending) order.
     * <p/>
     * Reversing delivery order takes more than negating {@link #compare(Object, Object)}: the
     * {@link ResequencerEngine} also relies on {@link #successor(Object, Object)} and
     * {@link #predecessor(Object, Object)} to detect gaps and to decide whether a buffered element already has its
     * immediate neighbour and can be released without waiting for its timeout. Since delivery now walks the sequence
     * from the highest to the lowest element, the element that used to be the immediate successor becomes the
     * immediate predecessor, and vice versa, so those two relations are swapped rather than left untouched.
     */
    private static final class ReverseSequenceElementComparator<E> implements SequenceElementComparator<E> {

        private final SequenceElementComparator<E> delegate;

        ReverseSequenceElementComparator(SequenceElementComparator<E> delegate) {
            this.delegate = delegate;
        }

        @Override
        public boolean predecessor(E o1, E o2) {
            return delegate.successor(o1, o2);
        }

        @Override
        public boolean successor(E o1, E o2) {
            return delegate.predecessor(o1, o2);
        }

        @Override
        public int compare(E o1, E o2) {
            return delegate.compare(o2, o1);
        }

        @Override
        public boolean isValid(E o1) {
            return delegate.isValid(o1);
        }

        @Override
        public String toString() {
            return "Reverse[" + delegate + "]";
        }
    }

}

